11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	};
18	
19	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
20	const PROCESSING_FEE = 5;
21	
22	export const processScenario = (scenario: Scenario): ScenarioResult => {
23	  const results = scenario.steps.map((step) => {
24	    const basePremium = step.items.reduce(
25	      (total, item) => total + BASE_PREMIUMS[item.type],
26	      0,
27	    );
28	    const firstInsuranceSurcharge =
29	      basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
30	    const premium = basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
31	    return { premium };
32	  });
33	  return { results };
34	};
