const quoteStep = (step: Step): StepResult => {
  const basePremium = step.items.reduce(
    (total, item) => total + BASE_PREMIUMS[item.type],
    0,
  );
  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
  const premium = basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
  return { premium };
};

export const processScenario = (scenario: Scenario): ScenarioResult => ({
  results: scenario.steps.map(quoteStep),
});
